                    <?php foreach ($data as $row): ?>
                        <?php $is_anomaly = ($row['anomaly_score'] == -1); ?>
                        <tr class="<?= $is_anomaly ? 'threat-row' : 'safe-row' ?>">
                            <td><?= $row['Time'] ?></td>
